// Vanilla C10PacketCreativeInventoryAction definition:
package net.minecraft.network.play.client;

import net.minecraft.item.ItemStack;
import net.minecraft.network.Packet;
import net.minecraft.network.PacketBuffer;
import net.minecraft.network.play.INetHandlerPlayServer;
import java.io.IOException;

public class C10PacketCreativeInventoryAction implements Packet<INetHandlerPlayServer> {
    private int slotId;
    private ItemStack stack;

    public C10PacketCreativeInventoryAction() {}
    public C10PacketCreativeInventoryAction(int slotIdIn, ItemStack stackIn) {
        this.slotId = slotIdIn;
        this.stack = stackIn != null ? stackIn.copy() : null;
    }

    public void readPacketData(PacketBuffer buf) throws IOException {
        this.slotId = buf.readShort();
        this.stack = buf.readItemStackFromBuffer();
    }

    public void writePacketData(PacketBuffer buf) throws IOException {
        buf.writeShort(this.slotId);
        buf.writeItemStackToBuffer(this.stack);
    }

    public void processPacket(INetHandlerPlayServer handler) {
        handler.processCreativeInventoryAction(this);
    }

    public int getSlotId() { return this.slotId; }
    public ItemStack getStack() { return this.stack; }
}

// Server-side validation:
// NetHandlerPlayServer.processCreativeInventoryAction():
public void processCreativeInventoryAction(C10PacketCreativeInventoryAction packetIn) {
    if (this.playerEntity.theItemInWorldManager.isCreative()) {
        boolean flag = packetIn.getSlotId() < 0 || packetIn.getSlotId() >= this.playerEntity.inventory.mainInventory.length;
        if (flag) {
            // Drop item on ground
        } else {
            this.playerEntity.inventory.setInventorySlotContents(packetIn.getSlotId(), packetIn.getStack());
            this.playerEntity.inventoryContainer.detectAndSendChanges();
        }
    }
}

